const p = msg.payload;

if (typeof p !== 'object' || p === null || Array.isArray(p)) {
    msg.error = 'payload no es un objeto JSON válido';
    return [null, msg];
}

const src = {
    room: p.room ?? p.habitacion,
    roomContext: p.contexto_hotel ?? p.room_context,
    timestamp: p.timestamp ?? p.timestamp_ms,
    temperature_C: p.temperature_C ?? p.temperatura_C,
    humidity_pct: p.humidity_pct ?? p.humedad_pct,
    mq135: p.mq135 ?? p.fosfina_mq135,
    mq7: p.mq7 ?? p.co_mq7,
    motion: p.motion ?? p.presencia_pir
};

const rawTimestamp = src.timestamp ?? new Date().toISOString();
let normalizedTimestamp = '';

if (typeof rawTimestamp === 'number' && Number.isFinite(rawTimestamp)) {
    const ts = rawTimestamp < 1e12 ? rawTimestamp * 1000 : rawTimestamp;
    normalizedTimestamp = new Date(ts).toISOString();
} else if (typeof rawTimestamp === 'string') {
    // Soporta ISO y epoch en string (segundos o milisegundos)
    if (/^\d+$/.test(rawTimestamp.trim())) {
        const epoch = Number(rawTimestamp);
        if (Number.isFinite(epoch)) {
            const ts = epoch < 1e12 ? epoch * 1000 : epoch;
            normalizedTimestamp = new Date(ts).toISOString();
        }
    } else {
        const isoParsed = Date.parse(rawTimestamp);
        if (Number.isFinite(isoParsed)) {
            normalizedTimestamp = new Date(isoParsed).toISOString();
        }
    }
}

const motionRaw = src.motion;
let motion = false;
if (typeof motionRaw === 'boolean') {
    motion = motionRaw;
} else if (typeof motionRaw === 'string') {
    const v = motionRaw.trim().toLowerCase();
    motion = v === '1' || v === 'true' || v === 'on' || v === 'si' || v === 'sí';
} else {
    motion = Number(motionRaw) > 0;
}

const out = {
    room: String(src.room ?? ''),
    room_context: String(src.roomContext ?? ''),
    timestamp: normalizedTimestamp,
    temperature_C: Number(src.temperature_C),
    humidity_pct: Number(src.humidity_pct),
    mq135: Number(src.mq135),
    mq7: Number(src.mq7),
    motion
};

const errors = [];
if (!out.room) errors.push('room requerido');
if (!out.timestamp) errors.push('timestamp inválido');
if (!Number.isFinite(out.temperature_C)) errors.push('temperature_C inválido');
if (!Number.isFinite(out.humidity_pct)) errors.push('humidity_pct inválido');
if (!Number.isFinite(out.mq135)) errors.push('mq135 inválido');
if (!Number.isFinite(out.mq7)) errors.push('mq7 inválido');

if (errors.length > 0) {
    msg.error = errors.join('; ');
    msg.validation_errors = errors;
    return [null, msg];
}

msg.payload = out;
return [msg, null];

const p = msg.payload;

const contextFromPayload = String(p?.room_context ?? p?.contexto_hotel ?? '').toUpperCase();
const validContexts = ['LIBRE', 'RESERVADA', 'FUMIGACION'];
let contexto = flow.get('estado_habitacion') || 'LIBRE';

if (validContexts.includes(contextFromPayload) && contextFromPayload !== contexto) {
    contexto = contextFromPayload;
    flow.set('estado_habitacion', contexto);
}

// ================================
// RANGOS DEL PDF (ppm)
// ================================
// PH3 (Fosfina): PEL 0.3, STEL 1.0, irritación 5-10, IDLH 50, letal 400-600
const PH3_PEL = Number(env.get('PH3_PEL_PPM') || 0.3);
const PH3_STEL = Number(env.get('PH3_STEL_PPM') || 1.0);
const PH3_IRRIT_LOW = Number(env.get('PH3_IRRIT_LOW_PPM') || 5);
const PH3_IRRIT_HIGH = Number(env.get('PH3_IRRIT_HIGH_PPM') || 10);
const PH3_IDLH = Number(env.get('PH3_IDLH_PPM') || 50);
const PH3_LETHAL_LOW = Number(env.get('PH3_LETHAL_LOW_PPM') || 400);

// CO: PEL 50, dolor leve 200, STEL 400, severo 800, IDLH 1500
const CO_PEL = Number(env.get('CO_PEL_PPM') || 50);
const CO_HEADACHE = Number(env.get('CO_HEADACHE_PPM') || 200);
const CO_STEL = Number(env.get('CO_STEL_PPM') || 400);
const CO_SEVERE = Number(env.get('CO_SEVERE_PPM') || 800);
const CO_IDLH = Number(env.get('CO_IDLH_PPM') || 1500);

// Temperatura de proceso
const TEMP_ALERTA = Number(env.get('TEMP_ALERTA_C') || 35);
const TEMP_INCENDIO = Number(env.get('UMBRAL_TEMP_INCENDIO') || 45);

// ================================
// CALIBRACIÓN RAW -> ppm (fallback)
// ================================
// Si no llega ppm explícito, se estima con escala lineal configurable.
const MQ135_MIN = Number(env.get('MQ135_RAW_MIN') || 0);
const MQ135_MAX = Number(env.get('MQ135_RAW_MAX') || 4095);
const MQ7_MIN = Number(env.get('MQ7_RAW_MIN') || 0);
const MQ7_MAX = Number(env.get('MQ7_RAW_MAX') || 4095);

const MQ135_PPM_MAX = Number(env.get('PH3_PPM_MAX_EST') || 120);
const MQ7_PPM_MAX = Number(env.get('CO_PPM_MAX_EST') || 2000);

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }
function mapRawToPpm(raw, inMin, inMax, outMax) {
    const x = clamp(Number(raw), inMin, inMax);
    const ratio = (x - inMin) / Math.max(1, (inMax - inMin));
    return ratio * outMax;
}

const ph3Ppm = Number.isFinite(Number(p.ph3_ppm))
    ? Number(p.ph3_ppm)
    : mapRawToPpm(p.mq135, MQ135_MIN, MQ135_MAX, MQ135_PPM_MAX);

const coPpm = Number.isFinite(Number(p.co_ppm))
    ? Number(p.co_ppm)
    : mapRawToPpm(p.mq7, MQ7_MIN, MQ7_MAX, MQ7_PPM_MAX);

let estado = 'NORMAL';
let razon = 'sin_alertas';
let nivel_alerta_detalle = 'NORMAL';
let color_alerta = 'green';

if (contexto === 'FUMIGACION') {
    if (p.motion) {
        estado = 'EMERGENCIA';
        razon = 'intruso_en_fumigacion';
        nivel_alerta_detalle = 'CRITICO: INTRUSO EN FUMIGACION';
        color_alerta = 'red';
    } else if (ph3Ppm >= PH3_IDLH || coPpm >= CO_IDLH || p.temperature_C >= TEMP_INCENDIO) {
        estado = 'EMERGENCIA';
        razon = 'riesgo_letal_en_fumigacion';
        nivel_alerta_detalle = 'CRITICO: RIESGO LETAL EN FUMIGACION';
        color_alerta = 'red';
    } else if (ph3Ppm >= PH3_PEL || coPpm >= CO_PEL || p.temperature_C >= TEMP_ALERTA) {
        estado = 'ALERTA';
        razon = 'operacion_fumigacion_vigilada';
        nivel_alerta_detalle = 'ALERTA: FUMIGACION ACTIVA BAJO VIGILANCIA';
        color_alerta = 'yellow';
    }
} else {
    if (ph3Ppm >= PH3_LETHAL_LOW || coPpm >= CO_IDLH || p.temperature_C >= TEMP_INCENDIO) {
        estado = 'EMERGENCIA';
        razon = 'riesgo_critico_ambiental';
        if (ph3Ppm >= PH3_LETHAL_LOW) nivel_alerta_detalle = 'CRITICO: FOSFINA NIVEL LETAL';
        else if (coPpm >= CO_IDLH) nivel_alerta_detalle = 'CRITICO: CO IDLH';
        else nivel_alerta_detalle = 'CRITICO: CONATO DE INCENDIO';
        color_alerta = 'red';
    } else if (ph3Ppm >= PH3_IDLH || coPpm >= CO_SEVERE || p.temperature_C >= TEMP_ALERTA) {
        estado = 'ALERTA';
        razon = 'riesgo_alto';
        if (ph3Ppm >= PH3_IDLH) nivel_alerta_detalle = 'ALERTA: FOSFINA SOBRE IDLH';
        else if (coPpm >= CO_SEVERE) nivel_alerta_detalle = 'ALERTA: CO NIVEL SEVERO';
        else nivel_alerta_detalle = 'ALERTA: TEMPERATURA ELEVADA';
        color_alerta = 'yellow';
    } else if (ph3Ppm >= PH3_IRRIT_LOW || coPpm >= CO_STEL) {
        estado = 'ALERTA';
        razon = 'riesgo_moderado';
        if (ph3Ppm >= PH3_IRRIT_LOW && ph3Ppm <= PH3_IRRIT_HIGH) nivel_alerta_detalle = 'ALERTA: IRRITACION POR FOSFINA';
        else if (coPpm >= CO_STEL) nivel_alerta_detalle = 'ALERTA: CO SOBRE STEL';
        color_alerta = 'yellow';
    } else if (ph3Ppm >= PH3_STEL || coPpm >= CO_HEADACHE) {
        estado = 'ALERTA';
        razon = 'riesgo_inicial';
        if (ph3Ppm >= PH3_STEL) nivel_alerta_detalle = 'ALERTA: FOSFINA SOBRE STEL';
        else nivel_alerta_detalle = 'ALERTA: CO POSIBLE CEFALEA';
        color_alerta = 'yellow';
    } else if (ph3Ppm >= PH3_PEL || coPpm >= CO_PEL) {
        estado = 'ALERTA';
        razon = 'sobre_pel';
        nivel_alerta_detalle = 'ALERTA: SOBRE LIMITE PERMISIBLE (PEL)';
        color_alerta = 'yellow';
    }
}

const statusText = `${estado} | ${nivel_alerta_detalle}`.slice(0, 64);
if (estado === 'EMERGENCIA') {
    node.status({ fill: 'red', shape: 'dot', text: statusText });
} else if (estado === 'ALERTA') {
    node.status({ fill: 'yellow', shape: 'dot', text: statusText });
} else {
    node.status({ fill: 'green', shape: 'dot', text: statusText });
}

msg.payload = {
    ...p,
    contexto_hotel: contexto,
    estado_riesgo: estado,
    razon_riesgo: razon,
    nivel_alerta: nivel_alerta_detalle,
    color_alerta,
    ph3_ppm: Number(ph3Ppm.toFixed(2)),
    co_ppm: Number(coPpm.toFixed(2)),
    backend_ts: Date.now()
};

return msg;

const p = msg.payload || {};

const habitacion = String(p.habitacion ?? p.room ?? '');
const contextoHotel = String(p.contexto_hotel ?? p.room_context ?? '');
const sistemaActivo = (typeof p.sistema_activo === 'boolean') ? p.sistema_activo : null;
const intervaloEnvio = Number.isFinite(Number(p.intervalo_envio_ms)) ? Number(p.intervalo_envio_ms) : null;
const fosfinaMq135 = Number.isFinite(Number(p.fosfina_mq135 ?? p.mq135)) ? Number(p.fosfina_mq135 ?? p.mq135) : null;
const coMq7 = Number.isFinite(Number(p.co_mq7 ?? p.mq7)) ? Number(p.co_mq7 ?? p.mq7) : null;
const presenciaPir = (p.presencia_pir ?? p.motion);
const presenciaInt = presenciaPir === null || presenciaPir === undefined ? null : ((presenciaPir === true || Number(presenciaPir) > 0) ? 1 : 0);
const eventoPir = p.evento_pir ?? null;
const temperaturaC = Number.isFinite(Number(p.temperatura_C ?? p.temperature_C)) ? Number(p.temperatura_C ?? p.temperature_C) : null;
const humedadPct = Number.isFinite(Number(p.humedad_pct ?? p.humidity_pct)) ? Number(p.humedad_pct ?? p.humidity_pct) : null;
const dhtOk = (typeof p.dht_ok === 'boolean') ? p.dht_ok : null;
const errorMsg = p.error ?? null;
const estadoRiesgo = p.estado_riesgo ?? null;
const razonRiesgo = p.razon_riesgo ?? null;
const nivelAlerta = p.nivel_alerta ?? null;
const colorAlerta = p.color_alerta ?? null;
const ph3Ppm = Number.isFinite(Number(p.ph3_ppm)) ? Number(p.ph3_ppm) : null;
const coPpm = Number.isFinite(Number(p.co_ppm)) ? Number(p.co_ppm) : null;
const backendTs = Number.isFinite(Number(p.backend_ts)) ? Number(p.backend_ts) : null;

if (!habitacion) {
    node.warn('INSERT omitido: habitacion vacía');
    return null;
}

msg.topic = 'INSERT INTO sensores (habitacion, timestamp, recibido_en, contexto_hotel, sistema_activo, intervalo_envio_ms, fosfina_mq135, co_mq7, presencia_pir, evento_pir, temperatura_C, humedad_pct, dht_ok, error, estado_riesgo, razon_riesgo, nivel_alerta, color_alerta, ph3_ppm, co_ppm, backend_ts) VALUES (?, NOW(), NOW(), ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);';

msg.payload = [
    habitacion,
    contextoHotel,
    sistemaActivo,
    intervaloEnvio,
    fosfinaMq135,
    coMq7,
    presenciaInt,
    eventoPir,
    temperaturaC,
    humedadPct,
    dhtOk,
    errorMsg,
    estadoRiesgo,
    razonRiesgo,
    nivelAlerta,
    colorAlerta,
    ph3Ppm,
    coPpm,
    backendTs
];

return msg;

msg.topic = 'SELECT * FROM sensores ORDER BY id DESC LIMIT 100;';
msg.payload = [];
return msg;

const risk = msg?.payload?.estado_riesgo;
if (!risk) return null;

const intervalByRisk = {
    NORMAL: Number(env.get('SAMPLE_MS_NORMAL') || 15000),
    ALERTA: Number(env.get('SAMPLE_MS_ALERTA') || 7000),
    EMERGENCIA: Number(env.get('SAMPLE_MS_EMERGENCIA') || 3000)
};

const intervalMs = Number(intervalByRisk[risk]);
if (!Number.isFinite(intervalMs) || intervalMs <= 0) return null;

const contexto = flow.get('estado_habitacion') || 'LIBRE';
const cmd = 'INICIAR';

const cooldownMs = Number(env.get('CMD_COOLDOWN_MS') || 15000);
const now = Date.now();
const lastAt = Number(flow.get('last_cmd_at') || 0);
const lastSig = flow.get('last_cmd_sig') || '';
const sig = `${cmd}|${contexto}|${intervalMs}`;

if ((now - lastAt) < cooldownMs && lastSig === sig) {
    return null;
}

flow.set('last_cmd_at', now);
flow.set('last_cmd_sig', sig);

msg.topic = env.get('TOPICO_COMANDOS') || 'alejandro.bravo_isa@uao.edu.co/comandos';
msg.payload = {
    msg: cmd,
    estado: contexto,
    sample_interval_ms: intervalMs
};
return msg;

const estado = msg?.payload?.estado;
const validos = ['LIBRE', 'RESERVADA', 'FUMIGACION'];
if (!validos.includes(estado)) {
    node.warn('estado invalido: ' + estado);
    return null;
}
flow.set('estado_habitacion', estado);
msg.topic = env.get('TOPICO_COMANDOS') || 'alejandro.bravo_isa@uao.edu.co/comandos';
return msg;
